/**
 * Connect to a BeeMl server over WebSocket.
 * @param url - WebSocket URL (e.g., "ws://localhost:9000")
 * @returns A connected BeeMlClient instance
 */
export async function connectBeeMl(
  url: string,
  options: SessionTransportOptions = {},
): Promise<BeeMlClient> {
  const established = await session.initiator(wsConnector(url), { ...options, metadata: voxServiceMetadata("BeeMl") });
  return new BeeMlClient(established.rootConnection().caller());
}

